/**
 * API Route Tests: /api/upload
 * Testa validação do endpoint de upload (extensão, tamanho, limite de slides)
 */

// Mock rate limit to always allow
jest.mock('@/lib/rate-limit', () => ({
  applyRateLimit: jest.fn().mockResolvedValue(null),
  checkRateLimit: jest.fn().mockResolvedValue({
    allowed: true,
    retryAfterSec: 0,
    remaining: 99,
    limit: 100,
    resetAtMs: Date.now() + 60_000,
    source: 'memory',
  }),
}));

// Mock logger
jest.mock('@/lib/logger', () => ({
  logger: {
    debug: jest.fn(),
    info: jest.fn(),
    warn: jest.fn(),
    error: jest.fn(),
  },
}));

// Mock auth — simula usuário autenticado
jest.mock('@lib/auth/unified-session', () => ({
  getServerAuth: jest.fn().mockResolvedValue({
    user: { id: 'test-user-id', email: 'test@example.com', name: 'Test User' },
  }),
}));

// Mock fs/promises para não escrever em disco
jest.mock('fs/promises', () => ({
  writeFile: jest.fn().mockResolvedValue(undefined),
  mkdir: jest.fn().mockResolvedValue(undefined),
  readFile: jest.fn().mockResolvedValue(Buffer.from('test')),
  access: jest.fn().mockResolvedValue(undefined),
}));

// Mock PPTXProcessorReal
const mockExtract = jest.fn();
const mockGenerateThumbnail = jest.fn().mockResolvedValue('/thumbnails/test.png');

jest.mock('@lib/pptx/pptx-processor-real', () => ({
  __esModule: true,
  default: {
    extract: mockExtract,
    generateThumbnail: mockGenerateThumbnail,
  },
}));

import { GET, POST } from '@/app/api/upload/route';
import { NextRequest } from 'next/server';

function createNextRequest(
  url: string,
  options?: { method?: string; body?: FormData; headers?: Record<string, string> }
): NextRequest {
  const init = {
    method: options?.method || 'GET',
    headers: options?.headers || {},
    ...(options?.body ? { body: options.body } : {}),
  };
  return new NextRequest(new URL(url, 'http://localhost:3000'), init as Parameters<typeof NextRequest['prototype']['clone']>[0] & Record<string, unknown>);
}

function createFileFromContent(name: string, content: string, type: string): File {
  return new File([content], name, { type });
}

describe('API /api/upload', () => {
  beforeEach(() => {
    jest.clearAllMocks();
    // Default: extraction returns 3 slides
    mockExtract.mockResolvedValue({
      success: true,
      slides: [
        { slideNumber: 1, title: 'Slide 1', content: 'Content 1' },
        { slideNumber: 2, title: 'Slide 2', content: 'Content 2' },
        { slideNumber: 3, title: 'Slide 3', content: 'Content 3' },
      ],
      metadata: { totalSlides: 3 },
    });
  });

  describe('GET /api/upload', () => {
    it('should return service info and allowed extensions', async () => {
      const req = createNextRequest('/api/upload');
      const response = await GET(req);
      const body = await response.json();

      expect(response.status).toBe(200);
      expect(body.service).toBe('Upload API');
      expect(body.allowedExtensions).toContain('.pptx');
      expect(body.allowedExtensions).toContain('.ppt');
      expect(body.allowedExtensions).toContain('.pdf');
    });
  });

  describe('POST /api/upload', () => {
    it('should reject request without multipart/form-data', async () => {
      const req = createNextRequest('/api/upload', {
        method: 'POST',
        headers: { 'content-type': 'application/json' },
      });
      const response = await POST(req);
      const body = await response.json();

      expect(response.status).toBe(400);
      expect(body.success).toBe(false);
      expect(body.error).toContain('multipart/form-data');
    });

    it('should reject upload without file', async () => {
      const formData = new FormData();
      const req = createNextRequest('/api/upload', {
        method: 'POST',
        body: formData,
      });
      const response = await POST(req);
      const body = await response.json();

      expect(response.status).toBe(400);
      expect(body.success).toBe(false);
      expect(body.error).toContain('obrigatório');
    });

    it('should reject invalid file extension', async () => {
      const formData = new FormData();
      formData.append('file', createFileFromContent('test.txt', 'hello', 'text/plain'));
      const req = createNextRequest('/api/upload', {
        method: 'POST',
        body: formData,
      });
      const response = await POST(req);
      const body = await response.json();

      expect(response.status).toBe(400);
      expect(body.success).toBe(false);
      expect(body.error).toContain('.pptx');
    });

    it('should accept valid PPTX file with slides under limit', async () => {
      const formData = new FormData();
      formData.append('file', createFileFromContent('test.pptx', 'pptx-content', 'application/vnd.openxmlformats-officedocument.presentationml.presentation'));
      formData.append('projectName', 'Test Project');

      const req = createNextRequest('/api/upload', {
        method: 'POST',
        body: formData,
      });
      const response = await POST(req);
      const body = await response.json();

      expect(response.status).toBe(201);
      expect(body.success).toBe(true);
      expect(body.slideCount).toBe(3);
      expect(body.projectName).toBe('Test Project');
      expect(body.slides).toHaveLength(3);
    });

    it('should accept PDF file extension', async () => {
      const formData = new FormData();
      formData.append('file', createFileFromContent('test.pdf', 'pdf-content', 'application/pdf'));

      const req = createNextRequest('/api/upload', {
        method: 'POST',
        body: formData,
      });
      const response = await POST(req);

      // PDF is accepted (processing may fallback, but the extension is valid)
      expect(response.status).not.toBe(400);
    });

    it('should reject presentation with more than 30 slides', async () => {
      // Mock extraction returning 35 slides
      const slides = Array.from({ length: 35 }, (_, i) => ({
        slideNumber: i + 1,
        title: `Slide ${i + 1}`,
        content: `Content ${i + 1}`,
      }));
      mockExtract.mockResolvedValue({
        success: true,
        slides,
        metadata: { totalSlides: 35 },
      });

      const formData = new FormData();
      formData.append('file', createFileFromContent('big.pptx', 'pptx-content', 'application/vnd.openxmlformats-officedocument.presentationml.presentation'));

      const req = createNextRequest('/api/upload', {
        method: 'POST',
        body: formData,
      });
      const response = await POST(req);
      const body = await response.json();

      expect(response.status).toBe(400);
      expect(body.success).toBe(false);
      expect(body.code).toBe('MAX_SLIDES_EXCEEDED');
      expect(body.slideCount).toBe(35);
      expect(body.maxSlides).toBe(30);
    });

    it('should accept presentation with exactly 30 slides', async () => {
      const slides = Array.from({ length: 30 }, (_, i) => ({
        slideNumber: i + 1,
        title: `Slide ${i + 1}`,
        content: `Content ${i + 1}`,
      }));
      mockExtract.mockResolvedValue({
        success: true,
        slides,
        metadata: { totalSlides: 30 },
      });

      const formData = new FormData();
      formData.append('file', createFileFromContent('exact30.pptx', 'pptx-content', 'application/vnd.openxmlformats-officedocument.presentationml.presentation'));

      const req = createNextRequest('/api/upload', {
        method: 'POST',
        body: formData,
      });
      const response = await POST(req);
      const body = await response.json();

      expect(response.status).toBe(201);
      expect(body.success).toBe(true);
      expect(body.slideCount).toBe(30);
    });
  });
});
